1	/**
2	 * LayerInfinite MCP Server — index.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * V2 Gateway Proxy entry point. Uses low-level Server (ADR-001)
5	 * for raw JSON-RPC interception of tools/list and tools/call.
6	 *
7	 * Registers handlers:
8	 *   tools/list   — enriched upstream tools + virtual li_recommend
9	 *   tools/call   — proxy to upstream, auto-mode rerouting
10	 *   resources/*  — gateway status + config (admin-gated)
11	 *   prompts/*    — setup instructions
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import { Server } from '@modelcontextprotocol/sdk/server/index.js';
16	import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js';
17	import {
18	  CallToolRequestSchema,
19	  ListToolsRequestSchema,
20	} from '@modelcontextprotocol/sdk/types.js';
21	
22	import { loadConfig } from './config.js';
23	import type { GatewayConfig } from './config.js';
24	import { LiApiClient, UpstreamMCPClient } from './rest-client.js';
25	import { UpstreamRegistry } from './upstream-registry.js';
26	import { GatewayProxy } from './gateway-proxy.js';
27	import { OutcomeClassifier } from './outcome-classifier.js';
28	import { DecisionTracker } from './decision-tracker.js';
29	import { startQueueProcessor } from './fail-open.js';
30	import type { QueueSender } from './fail-open.js';
31	import type { OutcomePayload } from './types.js';
32	import { logger } from './logger.js';
33	
34	const SERVER_NAME = 'layerinfinite-gateway';
35	const SERVER_VERSION = '2.0.0';
36	
37	const log = logger.forTool('index');
38	
39	// ── Task context extraction ─────────────────────────────────
40	
41	interface TaskContext {
42	  taskType: string;
43	  customerId: string;
44	  agentId: string;
45	}
46	
47	function extractTaskContext(params: Record<string, unknown> | undefined): TaskContext {
48	  const args = (params?.['arguments'] as Record<string, unknown>) ?? {};
49	  const meta = (params?.['_meta'] as Record<string, unknown>) ?? {};
50	
51	  const taskType = String(
52	    args['task_type'] ?? args['taskType'] ?? params?.['task_type'] ?? meta['taskType'] ?? 'unknown',
53	  );
54	
55	  const customerId = String(
56	    args['customer_id'] ??
57	      args['customerId'] ??
58	      params?.['customer_id'] ??
59	      process.env.LAYERINFINITE_DEFAULT_CUSTOMER ??
60	      'default',
61	  );
62	
63	  const agentId = String(
64	    meta['agentId'] ??
65	      args['agent_id'] ??
66	      args['agentId'] ??
67	      params?.['agent_id'] ??
68	      process.env.LAYERINFINITE_DEFAULT_AGENT ??
69	      'unknown',
70	  );
71	
72	  return { taskType, customerId, agentId };
73	}
74	
75	// ══════════════════════════════════════════════════════════════
76	// createGatewayServer
77	// ══════════════════════════════════════════════════════════════
78	
79	export interface GatewayServer {
80	  server: Server;
81	  proxy: GatewayProxy;
82	  config: GatewayConfig;
83	  upstreamClient: UpstreamMCPClient;
84	  registry: UpstreamRegistry;
85	  tracker: DecisionTracker;
86	  queueProcessor: { stop: () => void };
87	}
88	
89	export function createGatewayServer(): GatewayServer {
90	  const config = loadConfig();
91	  const registry = new UpstreamRegistry(config);
92	  const liApi = new LiApiClient(config);
93	  const upstreamClient = new UpstreamMCPClient(registry);
94	
95	  const classifier = config.classifier ? new OutcomeClassifier(config.classifier) : null;
96	  const tracker = new DecisionTracker(liApi);
97	  const proxy = new GatewayProxy(liApi, upstreamClient, registry, config, classifier, tracker);
98	
99	  // Start periodic queue processor for retrying failed outcome logs
100	  const queueSender: QueueSender = (payload: OutcomePayload) => liApi.logOutcome(payload);
101	  const queueProcessor = startQueueProcessor(queueSender, 30_000);
102	
103	  // Start periodic flush of tracker buffer (secondary durability)
104	  tracker.startFlushTimer();
105	
106	  const server = new Server(
107	    { name: SERVER_NAME, version: SERVER_VERSION },
108	    { capabilities: { tools: {}, resources: {}, prompts: {} } },
109	  );
110	
111	  const startedAt = Date.now();
112	
113	  // ── tools/list ──────────────────────────────────────────
114	
115	  server.setRequestHandler(ListToolsRequestSchema, async (request) => {
116	    try {
117	      const taskCtx = extractTaskContext(request.params as Record<string, unknown> | undefined);
118	      const enriched = await proxy.handleListTools(taskCtx);
119	
120	      // Strip internal fields (upstreamName, annotations) per MCP spec
121	      const tools = enriched.map((t) => ({
122	        name: t.name,
123	        description: t.description,
124	        inputSchema: t.inputSchema,
125	      }));
126	
127	      return { tools };
128	    } catch (err) {
129	      log.error('tools/list handler failed', {
130	        error: err instanceof Error ? err.message : String(err),
131	      });
132	      return { tools: [] };
133	    }
134	  });
135	
136	  // ── tools/call ──────────────────────────────────────────
137	
138	  server.setRequestHandler(CallToolRequestSchema, async (request) => {
139	    const toolName = request.params?.name ?? '';
140	    const args = (request.params?.arguments ?? {}) as Record<string, unknown>;
141	    const taskCtx = extractTaskContext(request.params as Record<string, unknown> | undefined);
142	
143	    try {
144	      const result = await proxy.handleCallTool(toolName, args, taskCtx);
145	      return result as unknown as { content: Array<{ type: string; text?: string }>; isError?: boolean };
146	    } catch (err) {
147	      const message = err instanceof Error ? err.message : String(err);
148	      log.error('tools/call handler failed', { tool: toolName, error: message });
149	      return {
150	        content: [{ type: 'text' as const, text: message }],
151	        isError: true,
152	      };
153	    }
154	  });
155	
156	  // ── resources/list ──────────────────────────────────────
157	
158	  server.setRequestHandler(
159	    { method: 'resources/list' } as never,
160	    async () => {
161	      try {
162	        const entries = registry.getAllUpstreams();
163	        const healthyCount = entries.filter((e) => registry.isHealthy(e.server.name)).length;
164	
165	        const resources = [
166	          {
167	            uri: 'li://gateway/status',
168	            name: 'Gateway Status',
169	            description: 'LayerInfinite Gateway Proxy runtime status',
170	            mimeType: 'text/plain',
171	          },
172	        ];
173	
174	        if (config.adminKey) {
175	          resources.push({
176	            uri: 'li://gateway/config',
177	            name: 'Gateway Configuration',
178	            description: 'Gateway config summary (requires admin key to read)',
179	            mimeType: 'application/json',
180	          });
181	        }
182	
183	        return { resources };
184	      } catch (err) {
185	        log.error('resources/list failed', { error: err instanceof Error ? err.message : String(err) });
186	        return { resources: [] };
187	      }
188	    },
189	  );
190	
191	  // ── resources/read ──────────────────────────────────────
192	
193	  server.setRequestHandler(
194	    { method: 'resources/read' } as never,
195	    async (request: { params?: { uri?: string } }) => {
196	      const uri = request.params?.uri ?? '';
197	
198	      try {
199	        if (uri === 'li://gateway/status') {
200	          const entries = registry.getAllUpstreams();
201	          const healthy = entries.filter((e) => registry.isHealthy(e.server.name));
202	          const uptimeMs = Date.now() - startedAt;
203	
204	          const status = {
205	            mode: config.mode ?? 'bootstrap',
206	            environment: config.environment,
207	            shadowMode: config.shadowMode,
208	            upstreams: {
209	              total: entries.length,
210	              healthy: healthy.length,
211	              names: entries.map((e) => e.server.name),
212	              healthyNames: healthy.map((e) => e.server.name),
213	            },
214	            uptime_seconds: Math.floor(uptimeMs / 1000),
215	            version: SERVER_VERSION,
216	          };
217	
218	          return {
219	            contents: [
220	              {
221	                uri,
222	                mimeType: 'text/plain',
223	                text: JSON.stringify(status, null, 2),
224	              },
225	            ],
226	          };
227	        }
228	
229	        if (uri === 'li://gateway/config') {
230	          return {
231	            contents: [
232	              {
233	                uri,
234	                mimeType: 'application/json',
235	                text: JSON.stringify(
236	                  {
237	                    mode: config.mode ?? 'bootstrap',
238	                    environment: config.environment,
239	                    shadowMode: config.shadowMode,
240	                    upstreamCount: config.upstreamServers.length,
241	                    modeOverrides: Object.fromEntries(config.modeOverrides),
242	                    apiKey: '[REDACTED]',
243	                    baseUrl: config.baseUrl,
244	                    adminEnabled: config.adminKey !== null,
245	                  },
246	                  null,
247	                  2,
248	                ),
249	              },
250	            ],
251	          };
252	        }
253	
254	        return {
255	          contents: [
256	            {
257	              uri,
258	              mimeType: 'text/plain',
259	              text: `Unknown resource: ${uri}`,
260	            },
261	          ],
262	        };
263	      } catch (err) {
264	        log.error('resources/read failed', { uri, error: err instanceof Error ? err.message : String(err) });
265	        return {
266	          contents: [{ uri, mimeType: 'text/plain', text: 'Error reading resource' }],
267	        };
268	      }
269	    },
270	  );
271	
272	  // ── prompts/list ────────────────────────────────────────
273	
274	  server.setRequestHandler(
275	    { method: 'prompts/list' } as never,
276	    async () => {
277	      return {
278	        prompts: [
279	          {
280	            name: 'layerinfinite-gateway-setup',
281	            description: 'LayerInfinite Gateway Proxy setup instructions',
282	            arguments: [],
283	          },
284	        ],
285	      };
286	    },
287	  );
288	
289	  // ── prompts/get ─────────────────────────────────────────
290	
291	  server.setRequestHandler(
292	    { method: 'prompts/get' } as never,
293	    async (request: { params?: { name?: string; arguments?: Record<string, unknown> } }) => {
294	      const name = request.params?.name ?? '';
295	
296	      if (name !== 'layerinfinite-gateway-setup') {
297	        return {
298	          messages: [
299	            {
300	              role: 'user' as const,
301	              content: { type: 'text' as const, text: `Unknown prompt: ${name}` },
302	            },
303	          ],
304	        };
305	      }
306	
307	      const text = [
308	        '# LayerInfinite Gateway Proxy Setup',
309	        '',
310	        'The LayerInfinite MCP Gateway Proxy transparently enriches your existing MCP tools with historical outcome intelligence.',
311	        '',
312	        '## Configuration',
313	        '',
314	        'Set these environment variables before starting:',
315	        '',
316	        '| Variable | Required | Description |',
317	        '|----------|----------|-------------|',
318	        '| `LAYERINFINITE_API_KEY` | Yes | Your LayerInfinite API key |',
319	        '| `LAYERINFINITE_UPSTREAM_TOOLS` | Yes | JSON array of upstream MCP servers (name, url, optional apiKey) |',
320	        '| `LAYERINFINITE_MODE` | No | Operating mode: `recommend`, `assist`, `auto` (omit for bootstrap) |',
321	        '| `LAYERINFINITE_MODE_OVERRIDES` | No | Per-task-type mode overrides as JSON object |',
322	        '| `LAYERINFINITE_SHADOW_MODE` | No | Set to `true` to observe without intervening |',
323	        '| `LAYERINFINITE_ENVIRONMENT` | No | `staging` or `production` (default: production) |',
324	        '| `LAYERINFINITE_BASE_URL` | No | API base URL (default: https://layerinfinite.me) |',
325	        '',
326	        '## Modes',
327	        '',
328	        '- **Bootstrap** (no mode set): Observe only — no enrichment or intervention',
329	        '- **Recommend**: Tool descriptions enriched with historical success rates',
330	        '- **Assist**: Recommendations + directional warnings based on history',
331	        '- **Auto**: Silent rerouting to the best tool based on outcome data',
332	        '',
333	        '## Upstream Format',
334	        '',
335	        '```json',
336	        '[',
337	        '  { "name": "github", "url": "https://github-mcp.example.com", "apiKey": "sk-..." },',
338	        '  { "name": "filesystem", "url": "http://localhost:8080" }',
339	        ']',
340	        '```',
341	        '',
342	        '## Starting the Gateway',
343	        '',
344	        '```bash',
345	        'npx @layerinfinite/mcp-server',
346	        '# or directly:',
347	        'node dist/bin/cli.js',
348	        '```',
349	        '',
350	        'The gateway connects via stdio — configure your MCP client to spawn this process.',
351	      ].join('\n');
352	
353	      return {
354	        messages: [
355	          {
356	            role: 'user' as const,
357	            content: { type: 'text' as const, text },
358	          },
359	        ],
360	      };
361	    },
362	  );
363	
364	  log.info('Gateway server created', {
365	    mode: config.mode ?? 'bootstrap',
366	    upstreams: config.upstreamServers.length,
367	    environment: config.environment,
368	    shadowMode: config.shadowMode,
369	    classifier: config.classifier ? `${config.classifier.model} (enabled)` : 'disabled',
370	  });
371	
372	  return { server, proxy, config, upstreamClient, registry, tracker, queueProcessor };
373	}
