1	/**
2	 * LayerInfinite MCP Server — gateway-proxy.ts
3	 * ══════════════════════════════════════════════════════════════
4	 * Core V2 Gateway Proxy. Intercepts tools/list (pre-reasoning
5	 * enrichment) and tools/call (proxy to upstream + auto-mode
6	 * rerouting). Natural language enrichment per mode — never
7	 * bracketed metadata.
8	 *
9	 * Phase 2 refactor: delegates enrichment to tool-enrichment.ts,
10	 * mode resolution to mode-manager.ts, score fetching to
11	 * score-fetcher.ts, and li_recommend to li-recommend-tool.ts.
12	 * ══════════════════════════════════════════════════════════════
13	 */
14	
15	import type { GatewayConfig } from './config.js';
16	import type {
17	  EnrichedTool,
18	  EnrichmentContext,
19	  OutcomePayload,
20	  GatewayMode,
21	} from './types.js';
22	import type { LiApiClient, UpstreamMCPClient, UpstreamCallResult } from './rest-client.js';
23	import type { UpstreamRegistry } from './upstream-registry.js';
24	import { enqueueOutcome } from './fail-open.js';
25	import { enrichToolList } from './tool-enrichment.js';
26	import { ModeManager } from './mode-manager.js';
27	import { ScoreFetcher } from './enrichment/score-fetcher.js';
28	import { createLiRecommendTool, handleLiRecommend } from './li-recommend-tool.js';
29	import { generateDecisionId } from './decision-tracker.js';
30	import { DecisionTracker } from './decision-tracker.js';
31	export { generateDecisionId };
32	import { OutcomeClassifier, classifyWithRules } from './outcome-classifier.js';
33	import type { OutcomeClassification } from './types.js';
34	import { logger } from './logger.js';
35	
36	const log = logger.forTool('gateway-proxy');
37	
38	// ── Auto-mode reroute threshold ─────────────────────────────
39	
40	const REROUTE_CONFIDENCE_THRESHOLD = 0.3;
41	
42	// ── Merge helper for agent-explicit > LLM-inferred > defaults ──
43	
44	function resolveMergeField(
45	  agentValue: string,
46	  llmValue: string | null,
47	  opts?: { exclude?: Set<string> },
48	): string | null {
49	  const exclude = opts?.exclude;
50	  if (agentValue && !exclude?.has(agentValue)) return agentValue;
51	  if (llmValue && !exclude?.has(llmValue)) return llmValue;
52	  return null;
53	}
54	
55	// ══════════════════════════════════════════════════════════════
56	// GatewayProxy
57	// ══════════════════════════════════════════════════════════════
58	
59	export class GatewayProxy {
60	  private readonly modeManager: ModeManager;
61	  private readonly scoreFetcher: ScoreFetcher;
62	
63	  constructor(
64	    private readonly liApi: LiApiClient,
65	    private readonly upstreamClient: UpstreamMCPClient,
66	    private readonly registry: UpstreamRegistry,
67	    private readonly config: GatewayConfig,
68	    private readonly classifier: OutcomeClassifier | null = null,
69	    private readonly tracker: DecisionTracker | null = null,
70	  ) {
71	    this.modeManager = new ModeManager(config);
72	    this.scoreFetcher = new ScoreFetcher(liApi);
73	  }
74	
75	  // ── tools/list handler ───────────────────────────────────
76	
77	  async handleListTools(taskContext: {
78	    taskType: string;
79	    customerId: string;
80	    agentId: string;
81	  }): Promise<EnrichedTool[]> {
82	    const mode = this.modeManager.resolveMode(taskContext.taskType);
83	
84	    try {
85	      const [rawTools, context] = await Promise.all([
86	        this.upstreamClient.listTools(),
87	        this.getEnrichmentContext(taskContext.taskType, taskContext.customerId, taskContext.agentId, mode),
88	      ]);
89	
90	      const enriched = enrichToolList(rawTools, context);
91	
92	      // Inject virtual li_recommend tool (only in non-bootstrap modes)
93	      if (mode !== 'bootstrap') {
94	        enriched.push(createLiRecommendTool());
95	      }
96	
97	      // Sort: ranked first, then alphabetically
98	      enriched.sort((a, b) => {
99	        const rankA = a.annotations?.ranking ?? 999;
100	        const rankB = b.annotations?.ranking ?? 999;
101	        if (rankA !== rankB) return rankA - rankB;
102	        return a.name.localeCompare(b.name);
103	      });
104	
105	      log.debug('tools/list enriched', {
106	        count: enriched.length,
107	        mode,
108	        taskType: taskContext.taskType,
109	      });
110	
111	      return enriched;
112	    } catch (err) {
113	      log.error('tools/list failed', { error: err instanceof Error ? err.message : String(err) });
114	      // Degrade: return raw tools with no enrichment
115	      try {
116	        const rawTools = await this.upstreamClient.listTools();
117	        return rawTools.map((t) => ({
118	          name: t.name,
119	          description: t.description,
120	          inputSchema: t.inputSchema,
121	          upstreamName: t.upstreamName,
122	        }));
123	      } catch {
124	        return [];
125	      }
126	    }
127	  }
128	
129	  // ── tools/call handler ───────────────────────────────────
130	
131	  async handleCallTool(
132	    toolName: string,
133	    args: Record<string, unknown>,
134	    taskContext: { taskType: string; customerId: string; agentId: string },
135	  ): Promise<UpstreamCallResult> {
136	    const decisionId = generateDecisionId(taskContext.agentId);
137	    const mode = this.modeManager.resolveMode(taskContext.taskType);
138	    const startMs = Date.now();
139	
140	    // Handle virtual li_recommend tool (delegated to li-recommend-tool.ts)
141	    if (toolName === 'li_recommend') {
142	      return handleLiRecommend(
143	        this.liApi,
144	        taskContext.taskType,
145	        taskContext.customerId,
146	        taskContext.agentId,
147	      );
148	    }
149	
150	    // Determine which tool to execute (auto-mode may reroute)
151	    let executedAction = toolName;
152	    let originalAction = toolName;
153	    let rerouted = false;
154	    let enrichmentScores: Record<string, number> = {};
155	
156	    if (mode === 'auto' && !this.config.shadowMode) {
157	      try {
158	        const [scores, policy] = await Promise.all([
159	          this.scoreFetcher.getScores(taskContext.taskType, taskContext.customerId, taskContext.agentId),
160	          this.liApi.getPolicyDecision(taskContext.taskType, taskContext.customerId, taskContext.agentId),
161	        ]);
162	
163	        for (const s of scores) {
164	          enrichmentScores[s.actionName] = s.compositeScore;
165	        }
166	
167	        if (
168	          policy &&
169	          policy.confidence >= REROUTE_CONFIDENCE_THRESHOLD &&
170	          policy.action !== toolName &&
171	          this.registry.isHealthy(this.resolveUpstream(policy.action))
172	        ) {
173	          originalAction = toolName;
174	          executedAction = policy.action;
175	          rerouted = true;
176	          log.info('Auto-mode reroute', {
177	            decisionId,
178	            from: toolName,
179	            to: policy.action,
180	            confidence: policy.confidence,
181	            reason: policy.reason,
182	          });
183	        }
184	      } catch {
185	        // Degrade — continue with original tool
186	      }
187	    }
188	
189	    // Resolve upstream from tool name
190	    const upstreamName = this.resolveUpstream(executedAction);
191	
192	    // Proxy to upstream
193	    const result = await this.upstreamClient.callTool(upstreamName, executedAction, args);
194	
195	    // Fire-and-forget outcome logging
196	    const latencyMs = Date.now() - startMs;
197	    void this.logDecision({
198	      decisionId,
199	      agentId: taskContext.agentId,
200	      customerId: taskContext.customerId,
201	      taskType: taskContext.taskType,
202	      actionName: executedAction,
203	      upstreamName,
204	      originalAction,
205	      executedAction,
206	      mode,
207	      rerouted,
208	      enrichmentScores,
209	      latencyMs,
210	      args,
211	      result,
212	      isError: result.isError === true,
213	    });
214	
215	    return result;
216	  }
217	
218	  // ── Shutdown ─────────────────────────────────────────────
219	
220	  async shutdown(): Promise<void> {
221	    this.registry.stopHealthChecks();
222	    log.info('Gateway proxy shut down');
223	  }
224	
225	  // ── Private: enrichment context ──────────────────────────
226	
227	  private async getEnrichmentContext(
228	    taskType: string,
229	    customerId: string,
230	    agentId: string,
231	    mode: GatewayMode,
232	  ): Promise<EnrichmentContext> {
233	    // Bootstrap mode — no enrichment needed
234	    if (mode === 'bootstrap') {
235	      return {
236	        taskType,
237	        customerId,
238	        agentId,
239	        mode,
240	        scores: [],
241	        policyDecision: null,
242	      };
243	    }
244	
245	    try {
246	      const [scores, policyDecision] = await Promise.all([
247	        this.scoreFetcher.getScores(taskType, customerId, agentId),
248	        this.liApi.getPolicyDecision(taskType, customerId, agentId),
249	      ]);
250	
251	      return { taskType, customerId, agentId, mode, scores, policyDecision };
252	    } catch (err) {
253	      log.warn('Enrichment context fetch failed — degrading to bootstrap-like', {
254	        error: err instanceof Error ? err.message : String(err),
255	      });
256	      return {
257	        taskType,
258	        customerId,
259	        agentId,
260	        mode,
261	        scores: [],
262	        policyDecision: null,
263	      };
264	    }
265	  }
266	
267	  // ── Private: routing helpers ─────────────────────────────
268	
269	  private resolveUpstream(toolName: string): string {
270	    const entries = this.registry.getAllUpstreams();
271	
272	    // Match tool name to upstream by prefix convention:
273	    // "github_push_fix" → upstream named "github"
274	    // "database_query" → upstream named "database"
275	    const prefix = toolName.split('_')[0];
276	    if (prefix) {
277	      const matched = entries.find(
278	        (e) => e.server.name === prefix && this.registry.isHealthy(e.server.name),
279	      );
280	      if (matched) return matched.server.name;
281	    }
282	
283	    // Fallback: first healthy upstream
284	    for (const entry of entries) {
285	      if (this.registry.isHealthy(entry.server.name)) return entry.server.name;
286	    }
287	    return entries[0]?.server.name ?? 'unknown';
288	  }
289	
290	  private async logDecision(record: {
291	    decisionId: string;
292	    agentId: string;
293	    customerId: string;
294	    taskType: string;
295	    actionName: string;
296	    upstreamName: string;
297	    originalAction: string;
298	    executedAction: string;
299	    mode: GatewayMode;
300	    rerouted: boolean;
301	    enrichmentScores: Record<string, number>;
302	    latencyMs: number;
303	    args?: Record<string, unknown>;
304	    result?: UpstreamCallResult;
305	    isError?: boolean;
306	  }): Promise<void> {
307	    try {
308	      // ── LLM classification (fire-and-forget, non-blocking) ────
309	      let classification: OutcomeClassification | null = null;
310	      if (this.classifier && record.result) {
311	        try {
312	          classification = await this.classifier.classify(
313	            record.actionName,
314	            record.args ?? {},
315	            record.result,
316	            record.isError ?? false,
317	            record.taskType,
318	          );
319	        } catch {
320	          // LLM failed — continue with defaults
321	        }
322	      }
323	
324	      // ── Rule-based fallback when LLM is unavailable ───────────
325	      if (!classification && record.result) {
326	        try {
327	          classification = classifyWithRules(
328	            record.actionName,
329	            record.args ?? {},
330	            record.result,
331	            record.isError ?? false,
332	            record.taskType,
333	          );
334	        } catch {
335	          // Rules failed — continue with defaults
336	        }
337	      }
338	
339	      // ── Merge: agent-explicit > LLM-inferred > defaults ──────
340	      const mergedTaskType = resolveMergeField(
341	        record.taskType,
342	        classification?.task_type ?? null,
343	        { exclude: new Set(['unknown', '', 'unspecified_issue']) },
344	      ) ?? 'unspecified_issue';
345	
346	      const mergedSuccess = record.isError === true ? false : (classification?.success ?? true);
347	
348	      // Build API-compatible payload. Omit decision_id — the gateway's
349	      // dec_ format is non-UUID and the API's schema accepts UUID only.
350	      const payload: OutcomePayload = {
351	        agent_id: record.agentId,
352	        customer_id: record.customerId,
353	        issue_type: mergedTaskType,
354	        action_name: record.actionName,
355	        upstream_name: record.upstreamName,
356	        original_action: record.originalAction,
357	        executed_action: record.executedAction,
358	        mode: record.mode,
359	        rerouted: record.rerouted,
360	        success: mergedSuccess,
361	        response_time_ms: record.latencyMs,
362	        timestamp: new Date().toISOString(),
363	        ingestion_source: 'mcp',
364	        environment: this.config.environment,
365	      };
366	
367	      // Attach classifier enrichment if available
368	      if (classification) {
369	        payload.context = classification.context;
370	        payload.error_message = classification.error_message;
371	        payload.result_summary = classification.result_summary;
372	        payload.classification_confidence = classification.confidence;
373	
374	        // Confidence gating: only attach business_outcome when confidence >= 0.7.
375	        // Low-confidence LLM classifications trigger false-positive silent-failure alerts.
376	        if (classification.confidence >= 0.7) {
377	          payload.business_outcome = classification.business_outcome;
378	        }
379	
380	        // Request delayed signal registration when confidence is low or outcome is ambiguous.
381	        // This auto-creates a pending_signal row so Layer 2/3 webhooks can resolve it later.
382	        if (
383	          classification.confidence < 0.7 ||
384	          classification.business_outcome === 'partial' ||
385	          classification.business_outcome === 'unknown'
386	        ) {
387	          payload.feedback_signal = 'delayed';
388	        }
389	      }
390	
391	      const sent = await this.liApi.logOutcome(payload);
392	      if (!sent) {
393	        await enqueueOutcome(payload);
394	      }
395	
396	      // ── Episode tracking (secondary durability) ───────────────
397	      this.tracker?.recordDecision({
398	        decisionId: record.decisionId,
399	        agentId: record.agentId,
400	        customerId: record.customerId,
401	        taskType: mergedTaskType,
402	        actionName: record.actionName,
403	        upstreamName: record.upstreamName,
404	        originalAction: record.originalAction,
405	        executedAction: record.executedAction,
406	        mode: record.mode,
407	        rerouted: record.rerouted,
408	        enrichmentScores: record.enrichmentScores,
409	        timestamp: new Date().toISOString(),
410	      });
411	    } catch {
412	      // Fire-and-forget — silent failure is acceptable
413	      log.debug('Outcome logging skipped (non-critical)');
414	    }
415	  }
416	}
