58	const VALID_MODES: ReadonlySet<string> = new Set(['recommend', 'assist', 'auto']);
59	const VALID_ENVIRONMENTS: ReadonlySet<string> = new Set(['staging', 'production']);
60	
61	function parseUpstreamServers(raw: string): UpstreamServer[] {
62	  try {
63	    const parsed = JSON.parse(raw);
64	    if (!Array.isArray(parsed)) {
65	      throw new Error('LAYERINFINITE_UPSTREAM_TOOLS must be a JSON array');
66	    }
67	    return parsed.map((item: Record<string, unknown>, i: number) => {
68	      if (typeof item.name !== 'string' || item.name.trim() === '') {
69	        throw new Error(`Upstream server at index ${i}: "name" is required and must be a non-empty string`);
70	      }
71	      if (typeof item.url !== 'string' || item.url.trim() === '') {
72	        throw new Error(`Upstream server "${item.name}": "url" is required and must be a non-empty string`);
73	      }
74	      return {
75	        name: item.name.trim(),
76	        url: item.url.trim(),
77	        apiKey: typeof item.apiKey === 'string' ? item.apiKey : undefined,
78	        healthCheckIntervalMs: typeof item.healthCheckIntervalMs === 'number' ? item.healthCheckIntervalMs : undefined,
79	      };
80	    });
81	  } catch (err) {
82	    if (err instanceof SyntaxError) {
83	      throw new Error(`LAYERINFINITE_UPSTREAM_TOOLS is not valid JSON: ${err.message}`);
84	    }
85	    throw err;
86	  }
87	}
88	
89	function parseModeOverrides(raw: string): Map<string, LIMode> {
90	  if (!raw || raw.trim() === '' || raw.trim() === '{}') {
91	    return new Map();
92	  }
93	  try {
94	    const parsed = JSON.parse(raw);
95	    if (typeof parsed !== 'object' || parsed === null || Array.isArray(parsed)) {
96	      throw new Error('LAYERINFINITE_MODE_OVERRIDES must be a JSON object (e.g., {"build_failed":"auto"})');
97	    }
98	    const map = new Map<string, LIMode>();
99	    for (const [taskType, mode] of Object.entries(parsed)) {
100	      if (typeof mode !== 'string' || !VALID_MODES.has(mode)) {
101	        throw new Error(
102	          `LAYERINFINITE_MODE_OVERRIDES: invalid mode "${String(mode)}" for task "${taskType}". ` +
103	          `Valid values: recommend, assist, auto.`,
104	        );
105	      }
106	      map.set(taskType, mode as LIMode);
107	    }
108	    return map;
109	  } catch (err) {
110	    if (err instanceof SyntaxError) {
111	      throw new Error(`LAYERINFINITE_MODE_OVERRIDES is not valid JSON: ${err.message}`);
112	    }
113	    throw err;
114	  }
115	}
